// Skip clustering: pass articles through with default General cluster
const articles = $('Input').all().map(i => i.json);
console.log('Clustering SKIPPED: ' + articles.length + ' articles passed through with cluster=General');
return articles.map(a => ({ json: { ...a, cluster: 0, cluster_label: 'General' } }));

// === CLUSTERING v2 - Formule amelioree + abstracts ===
const items = $input.all();
const articles = items.map(i => i.json);

if (articles.length < 3) {
  console.log('Clustering: < 3 articles, assigning General');
  return articles.map(a => ({ json: { ...a, cluster: 0, cluster_label: 'General' } }));
}

const BATCH_SIZE = 25;
// Formule amelioree: sqrt(n), plafond a 6, plancher a 2
// Evite la sur-segmentation tout en restant adaptatif
const targetClusters = Math.min(6, Math.max(2, Math.ceil(Math.sqrt(articles.length / 3))));
const minPerCluster = Math.max(2, Math.floor(articles.length / (targetClusters * 2)));
const batches = [];

for (let i = 0; i < articles.length; i += BATCH_SIZE) {
  const batch = articles.slice(i, i + BATCH_SIZE);
  const articleList = batch.map((a, j) => {
    const title = (a.title || 'No title').substring(0, 120);
    const abstract = (a.abstract || '').substring(0, 200);
    return j + ': ' + title + (abstract ? ' -- ' + abstract : '');
  }).join('\n');

  const prompt = `You are a scientific literature analyst specializing in thematic grouping. Organize these articles into coherent thematic clusters based on their content. Return ONLY valid JSON.\n\nArticles (index: title -- abstract excerpt):\n${articleList}\n\nReturn this exact JSON:\n{"clusters": [{"id": 0, "label": "Descriptive Theme Name", "articles": [0, 3, 7]}]}\n\nRULES:\n1. Create between 2 and ${targetClusters} clusters maximum.\n2. Each cluster MUST contain at least ${minPerCluster} articles. Do NOT create clusters with only 1 article.\n3. Each cluster label MUST be a descriptive thematic name (e.g. "Prevalence and Epidemiological Surveys", "Risk Factors and Determinants"), NOT generic names like "Cluster 1" or "Other".\n4. Every article index from 0 to ${batch.length - 1} must appear in exactly one cluster.\n5. Group articles by shared research themes, methodologies, or populations studied.\n6. Prefer fewer, broader clusters over many small ones. When in doubt, merge.`;

  batches.push({ json: { prompt, batchIndex: Math.floor(i / BATCH_SIZE), batchSize: batch.length, targetClusters } });
}

console.log('Clustering v2: ' + articles.length + ' articles -> ' + batches.length + ' batches, target ' + targetClusters + ' clusters (min ' + minPerCluster + '/cluster)');
return batches;

// === EXPAND v2 - Assign + consolidation intelligente ===
const responses = $input.all();
const originalItems = $('Input').all();
const articles = originalItems.map(i => i.json);
const BATCH_SIZE = 25;
const targetClusters = (responses[0] && responses[0].json.targetClusters) || 4;

const allLabels = new Array(articles.length).fill('Unclustered');
const batchLabels = [];

for (let r = 0; r < responses.length; r++) {
  const resp = responses[r].json;
  try {
    const responseText = resp.response || '';
    const inner = JSON.parse(responseText);
    (inner.clusters || []).forEach(cluster => {
      const label = cluster.label || ('Cluster ' + cluster.id);
      if (!batchLabels.includes(label)) batchLabels.push(label);
      (cluster.articles || []).forEach(idx => {
        const globalIdx = r * BATCH_SIZE + idx;
        if (globalIdx >= 0 && globalIdx < articles.length) {
          allLabels[globalIdx] = label;
        }
      });
    });
  } catch(e) {
    console.log('Clustering parse error batch ' + r + ': ' + e.message);
  }
}

const labelToId = {};
let nextId = 0;

const results = articles.map((article, i) => {
  const label = allLabels[i];
  if (!(label in labelToId)) labelToId[label] = nextId++;
  return { json: { ...article, cluster: labelToId[label], cluster_label: label } };
});

const uniqueLabels = [...new Set(allLabels.filter(l => l !== 'Unclustered'))];
console.log('Clustering: ' + articles.length + ' articles in ' + uniqueLabels.length + ' clusters');

// Consolidation si trop de clusters (multi-batch ou LLM qui segmente trop)
if (uniqueLabels.length > targetClusters) {
  console.log('Consolidation necessaire: ' + uniqueLabels.length + ' -> ' + targetClusters + ' clusters');
  return [{ json: {
    _needsConsolidation: true,
    _consolidateLabels: uniqueLabels,
    _targetClusters: targetClusters,
    _articles: results.map(r => r.json)
  }}];
}

return results;

// === CONSOLIDATION v2 - Fusion agressive avec description ===
const data = $input.all()[0].json;
const labels = data._consolidateLabels || [];
const tc = data._targetClusters || 4;
const articles = data._articles || [];

// Compter les articles par label pour aider le LLM
const labelCounts = {};
for (const a of articles) {
  const l = a.cluster_label || 'Unclustered';
  labelCounts[l] = (labelCounts[l] || 0) + 1;
}

const labelList = labels.map((l, i) => i + ': "' + l + '" (' + (labelCounts[l] || 0) + ' articles)').join('\n');

const prompt = `You are a scientific literature analyst. You must consolidate ${labels.length} thematic cluster labels into exactly ${tc} final clusters by merging similar themes. Return ONLY valid JSON.\n\nOriginal labels (with article counts):\n${labelList}\n\nRULES:\n1. Create exactly ${tc} consolidated clusters.\n2. Merge similar or overlapping themes together.\n3. Each consolidated label must be descriptive and thematic.\n4. Every original label must be mapped to exactly one consolidated label.\n5. Prefer merging small clusters into larger related ones.\n\nReturn: {"mapping": [{"original": "label text", "consolidated": "new broader label"}]}\nMap ALL ${labels.length} original labels.`;

return [{ json: { prompt, _articles: articles, _targetClusters: tc } }];

// === APPLY LABELS v2 - Fusion + renumerotation ===
const ollamaResp = $input.all()[0].json;
const prevData = $('Build Consolidation Prompt').first().json;
const articles = prevData._articles || [];

let labelMap = {};
try {
  const responseText = ollamaResp.response || '';
  const inner = JSON.parse(responseText);
  (inner.mapping || []).forEach(m => { labelMap[m.original] = m.consolidated; });
  console.log('Consolidation: ' + Object.keys(labelMap).length + ' labels fusionnes');
} catch(e) {
  console.log('Consolidation parse error: ' + e.message);
}

// Appliquer le mapping et renumeroter proprement
const labelToId = {};
let nextId = 0;
const results = articles.map(a => {
  let label = a.cluster_label || 'Unclustered';
  if (labelMap[label]) label = labelMap[label];
  if (!(label in labelToId)) labelToId[label] = nextId++;
  return { json: { ...a, cluster_label: label, cluster: labelToId[label] } };
});

// Log des clusters finaux
const clusterSizes = {};
results.forEach(r => {
  const l = r.json.cluster_label;
  clusterSizes[l] = (clusterSizes[l] || 0) + 1;
});
console.log('Clusters finaux:');
Object.entries(clusterSizes).forEach(([label, count]) => {
  console.log('  [' + count + '] ' + label);
});

return results;

// Pas de consolidation necessaire
const results = $input.all();
console.log('Clustering: sortie directe (pas de consolidation), ' + results.length + ' articles');
return results;
